    /// <summary>
    /// Uploads a single file (avatar or document) to wwwroot/uploads.
    /// Supports common image, PDF, and Office document types.
    /// </summary>
    /// <param name="file">The IFormFile representing the uploaded file.</param>
    /// <returns>An ActionResult containing the relative path to the saved file or an error message.</returns>
    [HttpPost("single")]
    [Consumes("multipart/form-data")]
    public async Task<IActionResult> UploadSingleFile([FromForm] IFormFile file)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest("No file uploaded.");
        }

        // --- File Validation ---
        // Define allowed file extensions
        var allowedExtensions = new List<string> {
            ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp", // Images
            ".pdf", // PDF
            ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx" // Office Documents
        };

        var fileExtension = Path.GetExtension(file.FileName)?.ToLowerInvariant();
        if (string.IsNullOrEmpty(fileExtension) || !allowedExtensions.Contains(fileExtension))
        {
            return BadRequest("File type not allowed. Allowed types: " + string.Join(", ", allowedExtensions));
        }

        // Max file size: 10 MB
        const long maxFileSize = 10 * 1024 * 1024; // 10 MB in bytes
        if (file.Length > maxFileSize)
        {
            return BadRequest($"File size exceeds the limit of {maxFileSize / (1024 * 1024)} MB.");
        }

        try
        {
            // Define the target uploads directory path within wwwroot
            var uploadsFolder = Path.Combine(_webHostEnvironment.WebRootPath, "uploads");

            // Create the directory if it doesn't exist
            if (!Directory.Exists(uploadsFolder))
